#include <stdio.h>
#include <stdlib.h>
int main(){
    int N,M; if(scanf("%d %d",&N,&M)!=2) return 0;
    int *win = (int*)malloc((N+1)*sizeof(int));
    for(int i=1;i<=N;i++) scanf("%d",&win[i]);
    char *has = (char*)calloc(N+1,sizeof(char));
    long long draught=0;
    for(int i=0;i<M;i++){
        int u,v; scanf("%d %d",&u,&v);
        if(win[u] && win[v]){ draught++; has[u]=1; has[v]=1; }
    }
    int rooms=0; for(int i=1;i<=N;i++) if(has[i]) rooms++;
    printf("%lld %d\n",draught,rooms);
    free(win); free(has);
    return 0;
}

