import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int N = fs.nextInt();
        int M = fs.nextInt();
        int[] win = new int[N+1];
        for (int i = 1; i <= N; i++) win[i] = fs.nextInt();
        boolean[] has = new boolean[N+1];
        long draught = 0;
        for (int i = 0; i < M; i++) {
            int u = fs.nextInt();
            int v = fs.nextInt();
            if (win[u] == 1 && win[v] == 1) {
                draught++;
                has[u] = true;
                has[v] = true;
            }
        }
        int rooms = 0;
        for (int i = 1; i <= N; i++) if (has[i]) rooms++;
        System.out.println(draught + " " + rooms);
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

