#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    M = int(next(it))
    win = [0] * (N + 1)
    for i in range(1, N + 1):
        win[i] = int(next(it))
    has = [False] * (N + 1)
    draught = 0
    for _ in range(M):
        u = int(next(it)); v = int(next(it))
        if win[u] and win[v]:
            draught += 1
            has[u] = has[v] = True
    rooms = sum(1 for i in range(1, N + 1) if has[i])
    print(draught, rooms)
if __name__ == "__main__":
    solve()

